mapper.delete:
DELETE FROM FWK_SYSTEM
WHERE GW_ID = #{gwId}
  AND SYSTEM_ID = #{systemId}

mapper.select:
SELECT 

WHERE s.GW_ID = #{gwId}
ORDER BY s.SYSTEM_ID

SELECT * FROM (
    SELECT
        ,
        ROW_NUMBER() OVER (ORDER BY s.GW_ID, s.SYSTEM_ID) AS RN



            AND s.GW_ID = #{gwId}


            AND s.OPER_MODE_TYPE = #{operModeType}


            AND s.STOP_YN = #{stopYn}


)
WHERE RN BETWEEN #{offset} + 1 AND #{offset} + #{limit}

SELECT COUNT(*)
FROM FWK_SYSTEM


        AND GW_ID = #{gwId}


        AND OPER_MODE_TYPE = #{operModeType}


        AND STOP_YN = #{stopYn}
